(window.webpackJsonp=window.webpackJsonp||[]).push([[400],{669:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">status</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">candies</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">keys</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">containedBoxes</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">initialBoxes</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxCandies = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">status, candies, keys, containedBoxes, initialBoxes</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> arr=[]\\n  <span class=\\"hljs-keyword\\">let</span> hasFetch={}\\n  <span class=\\"hljs-keyword\\">let</span> hasKey={}\\n  <span class=\\"hljs-keyword\\">let</span> hasBox={}\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;initialBoxes.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> id=initialBoxes[i]\\n    <span class=\\"hljs-keyword\\">if</span>(status[id]===<span class=\\"hljs-number\\">1</span>){\\n      arr.push(id)\\n      hasFetch[id]=<span class=\\"hljs-literal\\">true</span>\\n     \\n    }\\n     hasBox[id]=<span class=\\"hljs-literal\\">true</span>\\n  }\\n  \\n  \\n  <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> id=arr.shift()\\n      res+=candies[id]\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> key <span class=\\"hljs-keyword\\">of</span> keys[id]){\\n        hasKey[key]=<span class=\\"hljs-literal\\">true</span>\\n      }\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> boxId <span class=\\"hljs-keyword\\">of</span> containedBoxes[id]){\\n        hasBox[boxId]=<span class=\\"hljs-literal\\">true</span>\\n      }\\n    \\n      status[id]=<span class=\\"hljs-number\\">1</span>\\n      candies[id]=<span class=\\"hljs-number\\">0</span>\\n      keys[id]=[]\\n      containedBoxes[id]=[]\\n    }\\n    <span class=\\"hljs-built_in\\">console</span>.log(hasBox)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> boxKey <span class=\\"hljs-keyword\\">in</span> hasBox){\\n      <span class=\\"hljs-keyword\\">let</span> boxId=+boxKey\\n      <span class=\\"hljs-keyword\\">if</span>(hasFetch[boxId]){\\n        <span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">delete</span>(hasBox[boxId])\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(hasKey[boxId] || (status[boxId]===<span class=\\"hljs-number\\">1</span> &amp;&amp; !hasFetch[boxId])){\\n        hasFetch[boxId]=<span class=\\"hljs-literal\\">true</span>\\n        arr.push(boxId)\\n      }\\n      <span class=\\"hljs-comment\\">// hasBox[boxId]=true</span>\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-candies-you-can-get-from-boxes","hasThinking":false,"content":"<p>\u7ed9\u4f60&nbsp;<code>n</code>&nbsp;\u4e2a\u76d2\u5b50\uff0c\u6bcf\u4e2a\u76d2\u5b50\u7684\u683c\u5f0f\u4e3a&nbsp;<code>[status, candies, keys, containedBoxes]</code>&nbsp;\uff0c\u5176\u4e2d\uff1a</p>\\n\\n<ul>\\n\\t<li>\u72b6\u6001\u5b57&nbsp;<code>status[i]</code>\uff1a\u6574\u6570\uff0c\u5982\u679c&nbsp;<code>box[i]</code>&nbsp;\u662f\u5f00\u7684\uff0c\u90a3\u4e48\u662f <strong>1&nbsp;</strong>\uff0c\u5426\u5219\u662f <strong>0&nbsp;</strong>\u3002</li>\\n\\t<li>\u7cd6\u679c\u6570&nbsp;<code>candies[i]</code>: \u6574\u6570\uff0c\u8868\u793a&nbsp;<code>box[i]</code> \u4e2d\u7cd6\u679c\u7684\u6570\u76ee\u3002</li>\\n\\t<li>\u94a5\u5319&nbsp;<code>keys[i]</code>\uff1a\u6570\u7ec4\uff0c\u8868\u793a\u4f60\u6253\u5f00&nbsp;<code>box[i]</code>&nbsp;\u540e\uff0c\u53ef\u4ee5\u5f97\u5230\u4e00\u4e9b\u76d2\u5b50\u7684\u94a5\u5319\uff0c\u6bcf\u4e2a\u5143\u7d20\u5206\u522b\u4e3a\u8be5\u94a5\u5319\u5bf9\u5e94\u76d2\u5b50\u7684\u4e0b\u6807\u3002</li>\\n\\t<li>\u5185\u542b\u7684\u76d2\u5b50&nbsp;<code>containedBoxes[i]</code>\uff1a\u6574\u6570\uff0c\u8868\u793a\u653e\u5728&nbsp;<code>box[i]</code>&nbsp;\u91cc\u7684\u76d2\u5b50\u6240\u5bf9\u5e94\u7684\u4e0b\u6807\u3002</li>\\n</ul>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a&nbsp;<code>initialBoxes</code> \u6570\u7ec4\uff0c\u8868\u793a\u4f60\u73b0\u5728\u5f97\u5230\u7684\u76d2\u5b50\uff0c\u4f60\u53ef\u4ee5\u83b7\u5f97\u91cc\u9762\u7684\u7cd6\u679c\uff0c\u4e5f\u53ef\u4ee5\u7528\u76d2\u5b50\u91cc\u7684\u94a5\u5319\u6253\u5f00\u65b0\u7684\u76d2\u5b50\uff0c\u8fd8\u53ef\u4ee5\u7ee7\u7eed\u63a2\u7d22\u4ece\u8fd9\u4e2a\u76d2\u5b50\u91cc\u627e\u5230\u7684\u5176\u4ed6\u76d2\u5b50\u3002</p>\\n\\n<p>\u8bf7\u4f60\u6309\u7167\u4e0a\u8ff0\u89c4\u5219\uff0c\u8fd4\u56de\u53ef\u4ee5\u83b7\u5f97\u7cd6\u679c\u7684 <strong>\u6700\u5927\u6570\u76ee&nbsp;</strong>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>status = [1,0,1,0], candies = [7,5,4,100], keys = [[],[],[1],[]], containedBoxes = [[1,2],[3],[],[]], initialBoxes = [0]\\n<strong>\u8f93\u51fa\uff1a</strong>16\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u4e00\u5f00\u59cb\u4f60\u6709\u76d2\u5b50 0 \u3002\u4f60\u5c06\u83b7\u5f97\u5b83\u91cc\u9762\u7684 7 \u4e2a\u7cd6\u679c\u548c\u76d2\u5b50 1 \u548c 2\u3002\\n\u76d2\u5b50 1 \u76ee\u524d\u72b6\u6001\u662f\u5173\u95ed\u7684\uff0c\u800c\u4e14\u4f60\u8fd8\u6ca1\u6709\u5bf9\u5e94\u5b83\u7684\u94a5\u5319\u3002\u6240\u4ee5\u4f60\u5c06\u4f1a\u6253\u5f00\u76d2\u5b50 2 \uff0c\u5e76\u5f97\u5230\u91cc\u9762\u7684 4 \u4e2a\u7cd6\u679c\u548c\u76d2\u5b50 1 \u7684\u94a5\u5319\u3002\\n\u5728\u76d2\u5b50 1 \u4e2d\uff0c\u4f60\u4f1a\u83b7\u5f97 5 \u4e2a\u7cd6\u679c\u548c\u76d2\u5b50 3 \uff0c\u4f46\u662f\u4f60\u6ca1\u6cd5\u83b7\u5f97\u76d2\u5b50 3 \u7684\u94a5\u5319\u6240\u4ee5\u76d2\u5b50 3 \u4f1a\u4fdd\u6301\u5173\u95ed\u72b6\u6001\u3002\\n\u4f60\u603b\u5171\u53ef\u4ee5\u83b7\u5f97\u7684\u7cd6\u679c\u6570\u76ee = 7 + 4 + 5 = 16 \u4e2a\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>status = [1,0,0,0,0,0], candies = [1,1,1,1,1,1], keys = [[1,2,3,4,5],[],[],[],[],[]], containedBoxes = [[1,2,3,4,5],[],[],[],[],[]], initialBoxes = [0]\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u4f60\u4e00\u5f00\u59cb\u62e5\u6709\u76d2\u5b50 0 \u3002\u6253\u5f00\u5b83\u4f60\u53ef\u4ee5\u627e\u5230\u76d2\u5b50 1,2,3,4,5 \u548c\u5b83\u4eec\u5bf9\u5e94\u7684\u94a5\u5319\u3002\\n\u6253\u5f00\u8fd9\u4e9b\u76d2\u5b50\uff0c\u4f60\u5c06\u83b7\u5f97\u6240\u6709\u76d2\u5b50\u7684\u7cd6\u679c\uff0c\u6240\u4ee5\u603b\u7cd6\u679c\u6570\u4e3a 6 \u4e2a\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>status = [1,1,1], candies = [100,1,100], keys = [[],[0,2],[]], containedBoxes = [[],[],[]], initialBoxes = [1]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>status = [1], candies = [100], keys = [[]], containedBoxes = [[]], initialBoxes = []\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>status = [1,1,1], candies = [2,3,2], keys = [[],[],[]], containedBoxes = [[],[],[]], initialBoxes = [2,1,0]\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= status.length &lt;= 1000</code></li>\\n\\t<li><code>status.length == candies.length == keys.length == containedBoxes.length == n</code></li>\\n\\t<li><code>status[i]</code> \u8981\u4e48\u662f&nbsp;<code>0</code>&nbsp;\u8981\u4e48\u662f&nbsp;<code>1</code> \u3002</li>\\n\\t<li><code>1 &lt;= candies[i] &lt;= 1000</code></li>\\n\\t<li><code>0 &lt;= keys[i].length &lt;= status.length</code></li>\\n\\t<li><code>0 &lt;= keys[i][j] &lt; status.length</code></li>\\n\\t<li><code>keys[i]</code>&nbsp;\u4e2d\u7684\u503c\u90fd\u662f\u4e92\u4e0d\u76f8\u540c\u7684\u3002</li>\\n\\t<li><code>0 &lt;= containedBoxes[i].length &lt;= status.length</code></li>\\n\\t<li><code>0 &lt;= containedBoxes[i][j] &lt; status.length</code></li>\\n\\t<li><code>containedBoxes[i]</code>&nbsp;\u4e2d\u7684\u503c\u90fd\u662f\u4e92\u4e0d\u76f8\u540c\u7684\u3002</li>\\n\\t<li>\u6bcf\u4e2a\u76d2\u5b50\u6700\u591a\u88ab\u4e00\u4e2a\u76d2\u5b50\u5305\u542b\u3002</li>\\n\\t<li><code>0 &lt;= initialBoxes.length&nbsp;&lt;= status.length</code></li>\\n\\t<li><code>0 &lt;= initialBoxes[i] &lt; status.length</code></li>\\n</ul>\\n","title":"1298. \u4f60\u80fd\u4ece\u76d2\u5b50\u91cc\u83b7\u5f97\u7684\u6700\u5927\u7cd6\u679c\u6570","relatedTags":["\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1298"}')}}]);